CREATE DATABASE IF NOT EXISTS seating_db;
USE seating_db;
CREATE TABLE IF NOT EXISTS seat_status (
  seat_id INT PRIMARY KEY,
  event_id INT NOT NULL,
  seat_label VARCHAR(40) NOT NULL,
  section VARCHAR(40),
  seat_price DECIMAL(10,2),
  status ENUM('AVAILABLE','HELD','ALLOCATED') DEFAULT 'AVAILABLE',
  INDEX(event_id), INDEX(status)
);
CREATE TABLE IF NOT EXISTS seat_holds (
  hold_id BIGINT AUTO_INCREMENT PRIMARY KEY,
  seat_id INT NOT NULL,
  order_id VARCHAR(60) NOT NULL,
  user_id INT NOT NULL,
  expires_at DATETIME NOT NULL,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  UNIQUE KEY uniq_seat_active (seat_id),
  INDEX(order_id), INDEX(expires_at)
);
CREATE TABLE IF NOT EXISTS seat_allocations (
  allocation_id BIGINT AUTO_INCREMENT PRIMARY KEY,
  seat_id INT NOT NULL UNIQUE,
  order_id VARCHAR(60) NOT NULL,
  user_id INT NOT NULL,
  allocated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
